func fetchDevice(from urlString: String, requestData: [String : Any], completionBlock: @escaping ([String:Any]) -> Void){
        let url = URL(string:"\(urlString)")!
        var request = URLRequest(url: url)
        
        request.httpMethod = "GET"

        for (key, value) in requestData{
            if key == "Authorization"{
                continue;
            }
            
            request.setValue("\(value)", forHTTPHeaderField : key);
        }
        

        URLSession.shared.dataTask(with: request){ data , response,_ in
        
            let result = try! JSONSerialization.jsonObject(with: data!, options: []) as? [String : Any]
            completionBlock (result!)

        }.resume()
}

func uploadData(from urlString: String, requestData: [String : Any], completionBlock: @escaping ([String]) -> Void){
        let url = URL(string:"\(urlString)")!
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"

        
        for (key, value) in requestData{
            request.setValue("\(value)", forHTTPHeaderField : key);
            
        }
        guard let bodyData = try? JSONSerialization.data(withJSONObject: requestData, options: []) else { return}

        request.httpBody = bodyData
        
        
        

        URLSession.shared.dataTask(with:request) { data , response,_ in
            if let json = String (data: data!, encoding:.utf8){
                print("\(json)")
            }

        }.resume()
}